import { useState, useEffect } from 'react'
import { useQueryClient } from '@tanstack/react-query'
import {
  Box,
  List,
  ListItemButton,
  ListItemText,
  TextField,
  Button,
  IconButton,
  Typography,
  Divider,
  Tooltip,
  Stack,
} from '@mui/material'
import EditOutlinedIcon from '@mui/icons-material/EditOutlined'
import DeleteOutlineIcon from '@mui/icons-material/DeleteOutline'
import AddIcon from '@mui/icons-material/Add'

// Generated by: npm run generate-api
import {
  useListDesigns,
  useCreateDesign,
  useUpdateDesign,
  useDeleteDesign,
  getListDesignsQueryKey,
} from '../../../api/designs/designs'
import { useDesignStore } from '../designStore'

export default function DesignList() {
  const { activeDesignId, setActiveDesignId } = useDesignStore()
  const queryClient = useQueryClient()

  const [creating, setCreating] = useState(false)
  const [newName, setNewName] = useState('')
  const [editingId, setEditingId] = useState<string | null>(null)
  const [editName, setEditName] = useState('')

  const { data: designsPage } = useListDesigns()
  const designs = designsPage?.items ?? []

  const { mutate: createDesign } = useCreateDesign({
    mutation: {
      onSuccess: (newDesign) => {
        queryClient.invalidateQueries({ queryKey: getListDesignsQueryKey() })
        setActiveDesignId(newDesign.id as string)
      },
    },
  })

  const { mutate: updateDesign } = useUpdateDesign({
    mutation: {
      onSuccess: () => queryClient.invalidateQueries({ queryKey: getListDesignsQueryKey() }),
    },
  })

  const { mutate: deleteDesign } = useDeleteDesign({
    mutation: {
      onSuccess: (_data, vars) => {
        queryClient.invalidateQueries({ queryKey: getListDesignsQueryKey() })
        if (activeDesignId === vars.designId) {
          const remaining = designs.filter((d) => d.id !== vars.designId)
          setActiveDesignId((remaining[0]?.id as string) ?? null)
        }
      },
    },
  })

  useEffect(() => {
    if (designs.length > 0 && !activeDesignId) {
      setActiveDesignId(designs[0].id as string)
    }
  }, [designs, activeDesignId, setActiveDesignId])

  const handleCreate = () => {
    if (!newName.trim()) return
    createDesign({ data: { name: newName.trim() } })
    setNewName('')
    setCreating(false)
  }

  const handleRename = (id: string) => {
    if (editName.trim()) updateDesign({ designId: id, data: { name: editName.trim() } })
    setEditingId(null)
  }

  return (
    <Box
      sx={{
        width: 220,
        flexShrink: 0,
        display: 'flex',
        flexDirection: 'column',
        borderRight: 1,
        borderColor: 'divider',
        bgcolor: 'background.paper',
      }}
    >
      <Box sx={{ px: 2, py: 1.5, borderBottom: 1, borderColor: 'divider' }}>
        <Typography variant="subtitle2" fontWeight={600}>
          Designs
        </Typography>
        <Typography variant="caption" color="text.secondary">
          Shared with your lab
        </Typography>
      </Box>

      <List dense disablePadding sx={{ flex: 1, overflow: 'auto' }}>
        {designs.length === 0 && (
          <Typography
            variant="caption"
            color="text.disabled"
            sx={{ display: 'block', textAlign: 'center', mt: 4, px: 2 }}
          >
            No designs yet.
          </Typography>
        )}
        {designs.map((d) => (
          <ListItemButton
            key={d.id as string}
            selected={activeDesignId === (d.id as string)}
            onClick={() => {
              if (editingId !== d.id) setActiveDesignId(d.id as string)
            }}
            sx={{
              pr: 1,
              '& .item-actions': { opacity: 0, transition: 'opacity 0.15s' },
              '&:hover .item-actions': { opacity: 1 },
            }}
          >
            {editingId === d.id ? (
              <TextField
                autoFocus
                size="small"
                value={editName}
                onChange={(e) => setEditName(e.target.value)}
                onBlur={() => handleRename(d.id as string)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') handleRename(d.id as string)
                  if (e.key === 'Escape') setEditingId(null)
                }}
                onClick={(e) => e.stopPropagation()}
                variant="standard"
                sx={{ flex: 1 }}
                inputProps={{ style: { fontSize: 13 } }}
              />
            ) : (
              <>
                <ListItemText
                  primary={d.name}
                  primaryTypographyProps={{ fontSize: 13, noWrap: true }}
                />
                <Box className="item-actions" sx={{ display: 'flex', gap: 0.25 }}>
                  <Tooltip title="Rename">
                    <IconButton
                      size="small"
                      onClick={(e) => {
                        e.stopPropagation()
                        setEditingId(d.id as string)
                        setEditName(d.name)
                      }}
                    >
                      <EditOutlinedIcon sx={{ fontSize: 14 }} />
                    </IconButton>
                  </Tooltip>
                  <Tooltip title="Delete">
                    <IconButton
                      size="small"
                      color="error"
                      onClick={(e) => {
                        e.stopPropagation()
                        if (confirm(`Delete "${d.name}"?`))
                          deleteDesign({ designId: d.id as string })
                      }}
                    >
                      <DeleteOutlineIcon sx={{ fontSize: 14 }} />
                    </IconButton>
                  </Tooltip>
                </Box>
              </>
            )}
          </ListItemButton>
        ))}
      </List>

      <Divider />

      <Box sx={{ p: 1.5 }}>
        {creating ? (
          <Stack direction="row" spacing={0.5}>
            <TextField
              autoFocus
              size="small"
              value={newName}
              onChange={(e) => setNewName(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter') handleCreate()
                if (e.key === 'Escape') setCreating(false)
              }}
              placeholder="Design name..."
              fullWidth
              inputProps={{ style: { fontSize: 12 } }}
            />
            <Button
              variant="contained"
              size="small"
              onClick={handleCreate}
              sx={{ minWidth: 0, px: 1.5 }}
            >
              Add
            </Button>
          </Stack>
        ) : (
          <Button
            fullWidth
            variant="contained"
            size="small"
            startIcon={<AddIcon />}
            onClick={() => setCreating(true)}
          >
            New Design
          </Button>
        )}
      </Box>
    </Box>
  )
}
